beforeSaveCustomScript:
$amountCTC = entity\attribute('amountCTC');
/*
 * Get package configuration
 */

$basicPercent = payPackage.basicPay;
$hraPercent = payPackage.hRAGross; 
$conveyance = payPackage.conveyanceAllowance;
$medical = payPackage.medical;
$ptGross = payPackage.pTGross;
$balancingFigure = payPackage.balancingFigure;


$grossSalary = $amountCTC/12 ;
entity\setAttribute('grossSalary', $grossSalary);

// 50%
$updatedBasicPay = ($grossSalary * $basicPercent) / 100;
entity\setAttribute('basicPay', $updatedBasicPay);

// 40%
$updatedHRA = ($updatedBasicPay * $hraPercent) / 100;
entity\setAttribute('hRAGross', $updatedHRA);

// Fixed
entity\setAttribute('conveyanceAllowance', payPackage.conveyanceAllowance);
entity\setAttribute('medical', payPackage.medical);

// Special Allowance = Gross - (Basic Pay-HRA-Conveyance-Medical)
$updatedSpecialAllowance = $grossSalary - ($updatedBasicPay + $updatedHRA + payPackage.medical + payPackage.conveyanceAllowance);
entity\setAttribute('specialAllowance', $updatedSpecialAllowance);
